<script setup>import {onMounted,ref} from 'vue';import {getMemberRepairs} from '../api/repairApi';const list=ref([]),loading=ref(true),error=ref('');const labels={SUBMITTED:'已送出',RECEIVED:'已收件',INSPECTING:'檢測中',QUOTED:'已報價',WAITING_APPROVAL:'等待確認',WAITING_PARTS:'等待零件',REPAIRING:'維修中',COMPLETED:'已完成',PICKED_UP:'已取件',RETURNED:'已歸還',CANCELLED:'已取消'};onMounted(async()=>{try{list.value=await getMemberRepairs()}catch(e){error.value=e.message}finally{loading.value=false}})</script>
<template><section class="member-section"><div class="page-heading"><div><span class="eyebrow">MY REPAIRS</span><h1>我的維修</h1><p>集中查看送修裝置與服務進度。</p></div><RouterLink class="button button-primary" to="/repairs">新增維修申請</RouterLink></div><p v-if="error" class="alert alert-error">{{error}}</p><div v-if="loading" class="loading-state">正在載入維修紀錄…</div><div v-else-if="!list.length" class="empty-state"><h2>目前沒有維修紀錄</h2><RouterLink class="button button-primary" to="/repairs">提出申請</RouterLink></div><div v-else class="record-grid"><RouterLink v-for="item in list" :key="item.id" class="record-card card" :to="`/member/repairs/${item.id}`"><span class="badge">{{labels[item.repairStatus]||item.repairStatus}}</span><h2>{{item.deviceBrand}} {{item.deviceModel}}</h2><p>案件編號 RP-{{item.id}}</p><small>{{new Date(item.createdAt).toLocaleString('zh-TW')}}</small></RouterLink></div></section></template>
